interface:
interface MonitorReport {
  anomalies: Array<{ moduleId: string; type: 'low-confidence' | 'unexpected-result' | 'compound'; detail: string }>;
  escalation?: string;
  restrictedActions: string[];
  forceReplan: boolean;
}

grammar:
MonitorReport
  = a:AnomaliesSection EOL e:EscalationSection EOL r:RestrictSection EOL p:ReplanSection EOLopt
    { return { anomalies: a, escalation: e, restrictedActions: r, forceReplan: p }; }

AnomaliesSection
  = "ANOMALIES:" _ "none" { return []; }
  / "ANOMALIES:" EOL list:AnomalyList { return list; }

AnomalyList
  = first:AnomalyLine rest:(EOL a:AnomalyLine { return a; })* { return [first, ...rest]; }

AnomalyLine
  = "@" moduleId:Identifier _ anomalyType:AnomalyType _ detail:QuotedString
    { return { moduleId, type: anomalyType, detail }; }

AnomalyType
  = "low-confidence" / "unexpected-result" / "compound"

EscalationSection
  = "ESCALATE:" _ "none" { return undefined; }
  / "ESCALATE:" _ msg:QuotedString { return msg; }

RestrictSection
  = "RESTRICT:" _ "none" { return []; }
  / "RESTRICT:" _ first:Identifier rest:("," _ id:Identifier { return id; })* { return [first, ...rest]; }

ReplanSection
  = "REPLAN:" _ "yes" { return true; }
  / "REPLAN:" _ "no" { return false; }

Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

