PrioritySection
  = "PRIORITY:" _ v:("high" / "medium" / "low") { return v; }

FocusSection
  = "FOCUS:" _ "none" { return []; }
  / "FOCUS:" _ first:Identifier rest:("," _ id:Identifier { return id; })* { return [first, ...rest]; }

NoveltySection
  = "NOVELTY:" _ v:Float { return v; }

NoteSection
  = "NOTE:" _ "none" { return null; }
  / "NOTE:" _ v:QuotedString { return v; }

Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$[0-9]+ "." frac:$[0-9]+ { return parseFloat(chars + '.' + frac); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

