interface:
interface ReasonerOutput {
  trace: string;
  confidence: number;
  conflictDetected: boolean;
  action?: { tool: string; args: Record<string, string> };
}

grammar:
ReasonerOutput
  = t:TraceSection EOL c:ConfidenceSection EOL d:ConflictSection act:ActionOpt EOLopt
    { return { trace: t, confidence: c, conflictDetected: d, action: act }; }

TraceSection
  = "TRACE:" _ v:QuotedString { return v; }

ConfidenceSection
  = "CONFIDENCE:" _ v:Float { return v; }

ConflictSection
  = "CONFLICT:" _ v:("yes" { return true; } / "no" { return false; }) { return v; }

ActionOpt
  = EOL "ACTION:" _ tool:Identifier args:ArgsOpt { return { tool, args: args || {} }; }
  / "" { return undefined; }

ArgsOpt
  = _ "{" _ first:ArgPair rest:("," _ p:ArgPair { return p; })* _ "}" { return Object.fromEntries([first, ...rest]); }
  / "" { return {}; }

ArgPair
  = k:Identifier ":" _ v:QuotedString { return [k, v]; }

Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$[0-9]+ ("." $[0-9]+)? { return parseFloat(text()); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

