grammar:
EvictionInfo
  = r:ReasonSection EOL s:SalienceSection delta:DeltaOpt EOL t:TimestampSection EOLopt
    { return { reason: r, salience: s, salienceDelta: delta, timestamp: t }; }

ReasonSection
  = "REASON:" _ v:("capacity" / "ttl") { return v; }

SalienceSection
  = "SALIENCE:" _ v:SignedFloat { return v; }

DeltaOpt
  = EOL "SALIENCE_DELTA:" _ v:SignedFloat { return v; }
  / "" { return undefined; }

TimestampSection
  = "TIMESTAMP:" _ v:Float { return v; }

SignedFloat = s:$("-"? [0-9]+ ("." [0-9]+)?) { return parseFloat(s); }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

