interface:
interface TimelineOptions {
  twinId?: string;
  since?: string;
  until?: string;
  types?: Array<'decision' | 'observation' | 'reflection' | 'action'>;
  limit?: number;
}

grammar:
TimelineOptions
  = parts:OptionPart* EOLopt
    { const obj = {}; for (const p of parts) obj[p[0]] = p[1]; return obj; }

OptionPart
  = EOL? p:(TwinIdOpt / SinceOpt / UntilOpt / TypesOpt / LimitOpt) { return p; }

TwinIdOpt
  = "TWIN_ID:" _ v:QuotedString { return ['twinId', v]; }

SinceOpt
  = "SINCE:" _ v:QuotedString { return ['since', v]; }

UntilOpt
  = "UNTIL:" _ v:QuotedString { return ['until', v]; }

TypesOpt
  = "TYPES:" _ "none" { return ['types', []]; }
  / "TYPES:" _ first:ActionType rest:("," _ t:ActionType { return t; })* { return ['types', [first, ...rest]]; }

ActionType
  = "decision" / "observation" / "reflection" / "action"

LimitOpt
  = "LIMIT:" _ v:Integer { return ['limit', v]; }

Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

